import React, { useEffect, useState } from 'react'
import { farmService } from '../../services/api'

const OwnerFarms = () => {
  const [farms, setFarms] = useState([])
  const [loading, setLoading] = useState(false)
  const [form, setForm] = useState({ farm_code: '', farm_name: '', location: '', area_hectare: '' })
  const [editingId, setEditingId] = useState(null)
  const [error, setError] = useState('')

  const loadFarms = async () => {
    setLoading(true)
    try {
      const res = await farmService.getFarms()
      setFarms(res.data.data || [])
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    loadFarms()
  }, [])

  const handleChange = (e) => {
    const { name, value } = e.target
    setForm((f) => ({ ...f, [name]: value }))
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    try {
      if (editingId) {
        await farmService.updateFarm(editingId, form)
        setEditingId(null)
      } else {
        await farmService.createFarm(form)
      }
      setForm({ farm_code: '', farm_name: '', location: '', area_hectare: '' })
      await loadFarms()
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    }
  }

  const handleEdit = (farm) => {
    setEditingId(farm.farm_id)
    setForm({
      farm_code: farm.farm_code || '',
      farm_name: farm.farm_name || '',
      location: farm.location || '',
      area_hectare: farm.area_hectare || '',
    })
  }

  const handleDelete = async (farmId) => {
    if (!window.confirm('Bạn có chắc chắn muốn xóa trại này?')) return
    try {
      await farmService.deleteFarm(farmId)
      await loadFarms()
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    }
  }

  return (
    <div style={{ padding: 20 }}>
      <h2>Quản lý Trại nuôi</h2>
      {error && <div className="alert alert-error">{error}</div>}

      <form onSubmit={handleSubmit} style={{ marginBottom: 20, maxWidth: 700 }}>
        <div className="form-group">
          <label>Mã trại</label>
          <input name="farm_code" value={form.farm_code} onChange={handleChange} required />
        </div>
        <div className="form-group">
          <label>Tên trại</label>
          <input name="farm_name" value={form.farm_name} onChange={handleChange} required />
        </div>
        <div className="form-group">
          <label>Địa điểm</label>
          <input name="location" value={form.location} onChange={handleChange} />
        </div>
        <div className="form-group">
          <label>Diện tích (ha)</label>
          <input name="area_hectare" value={form.area_hectare} onChange={handleChange} />
        </div>

        <button className="btn btn-primary" type="submit">{editingId ? 'Cập nhật' : 'Tạo trại'}</button>
        {editingId && (
          <button type="button" className="btn" onClick={() => { setEditingId(null); setForm({ farm_code: '', farm_name: '', location: '', area_hectare: '' }) }}>Hủy</button>
        )}
      </form>

      <h3>Danh sách trại</h3>
      {loading ? (
        <p>Đang tải...</p>
      ) : (
        <table className="table">
          <thead>
            <tr>
              <th>#</th>
              <th>Mã</th>
              <th>Tên</th>
              <th>Địa điểm</th>
              <th>Diện tích (ha)</th>
              <th>Hành động</th>
            </tr>
          </thead>
          <tbody>
            {farms.map((f, idx) => (
              <tr key={f.farm_id}>
                <td>{idx + 1}</td>
                <td>{f.farm_code}</td>
                <td>{f.farm_name}</td>
                <td>{f.location}</td>
                <td>{f.area_hectare}</td>
                <td>
                  <button className="btn" onClick={() => handleEdit(f)}>Sửa</button>
                  <button className="btn btn-danger" onClick={() => handleDelete(f.farm_id)}>Xóa</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  )
}

export default OwnerFarms
